// FASE 1.1a Cloudflare Worker "The Gatekeeper"
export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);

    // 0. IGNORAR archivos estáticos y API internas (evita bucle infinito de telemetría de las barras)
    if (url.pathname.startsWith('/api/') || url.pathname.match(/\.(js|css|png|jpg|jpeg|gif|ico|json|md)$/i)) {
        return fetch(request);
    }

    // 1. Manejar el "Sello" (Cookie) para saber si es visita nueva o recurrente
    const cookieHeader = request.headers.get("Cookie") || "";
    let visitorId = null;
    let isNewVisitor = true;

    // Buscar si ya tiene nuestro sello
    const cookies = cookieHeader.split(';').map(c => c.trim());
    for (const c of cookies) {
      if (c.startsWith("netmarlyn_uid=")) {
        visitorId = c.substring("netmarlyn_uid=".length);
        isNewVisitor = false;
        break;
      }
    }

    // Si es nuevo, crearle un sello único simple (ej. timestamp + random)
    if (!visitorId) {
      visitorId = 'uid_' + Date.now().toString(36) + Math.random().toString(36).substring(2, 7);
    }

    // 2. Extraer TODA la data posible de Cloudflare (Latitud, Longitud, ISP, Ciudad, País)
    const ip = request.headers.get("CF-Connecting-IP") || "0.0.0.0";
    const cf = request.cf || {};

    // Fingerprinting Básico: Leer el "DNI" del navegador (User-Agent)
    const userAgent = request.headers.get('User-Agent') || 'Desconocido';
    let os = "Desconocido";
    let browser = "Desconocido";

    // Extracción veloz de OS
    if (userAgent.includes("Win")) os = "Windows";
    else if (userAgent.includes("Mac")) os = "macOS";
    else if (userAgent.includes("iPhone") || userAgent.includes("iPad")) os = "iOS";
    else if (userAgent.includes("Android")) os = "Android";
    else if (userAgent.includes("Linux")) os = "Linux";

    // Extracción veloz de Browser
    if (userAgent.includes("Chrome") && !userAgent.includes("Edg")) browser = "Chrome";
    else if (userAgent.includes("Safari") && !userAgent.includes("Chrome")) browser = "Safari";
    else if (userAgent.includes("Firefox")) browser = "Firefox";
    else if (userAgent.includes("Edg")) browser = "Edge";

    const telemetryPayload = {
      visitor_id: visitorId,
      is_new: isNewVisitor,
      ip: ip,
      country: cf.country || request.headers.get("CF-IPCountry") || "Desconocido",
      city: cf.city || "Desconocida",
      region: cf.region || "Desconocida",
      latitude: cf.latitude || null,
      longitude: cf.longitude || null,
      asn: cf.asn || null,
      asOrganization: cf.asOrganization || "Desconocido",
      timezone: cf.timezone || "Desconocido",
      continent: cf.continent || "Desconocido",
      postalCode: cf.postalCode || "Desconocido",
      colo: cf.colo || "Desconocido",
      tlsVersion: cf.tlsVersion || "Desconocida",
      deviceType: request.headers.get("CF-Device-Type") || "Desktop/Móvil", // CF Mobile Redirect setting
      os: os, // Apple, Windows, Android...
      browser: browser, // Chrome, Safari...
      userAgentFull: userAgent, // Toda la firma de la computadora/celular (Dell, Toshiba, Samsung...)
      timestamp: new Date().toISOString(),
      path: url.pathname
    };

    // 3. Enviar esto a la Mac Studio (Futura Mac Mini) de forma asíncrona
    // Se enviará por POST al túnel para que el programa local lo guarde en el .json
    ctx.waitUntil(
      fetch("https://www.netmarlyn.site/api/visitas", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(telemetryPayload)
      }).catch(err => console.error("Fallo al registrar en servidor local"))
    );

    // 4. Intentar cargar el sitio real (Mac Studio vía Túnel)
    try {
      let response = await fetch(request);

      // Si el sitio local está caído
      if (response.status >= 500) {
        throw new Error("Servidor Local Caído");
      }

      // Si es un visitante nuevo, inyectar la cookie (Sello) en la respuesta
      if (isNewVisitor) {
        // Clonar la respuesta para poder modificar los headers
        response = new Response(response.body, response);
        // La cookie expira en 1 año (31536000 max-age)
        response.headers.append(
          "Set-Cookie",
          `netmarlyn_uid=${visitorId}; Max-Age=31536000; Path=/; Secure; HttpOnly; SameSite=Lax`
        );
      }

      return response;
    } catch (error) {
      // 5. Fallback Automático: Sitio Caído. Mostrar Imagen Negra Centrada.
      const b64image = "data:image/jpeg;base64,";

      const maintenanceHTML = `<!DOCTYPE html>
<html lang="es">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>NetMarlyn - Sitio en Mantenimiento</title>
    <style>
        body, html { margin: 0; padding: 0; height: 100%; background-color: #000; display: flex; justify-content: center; align-items: center; overflow: hidden; }
        img { width: 800px; height: 700px; object-fit: contain; max-width: 100vw; max-height: 100vh; }
    </style>
</head>
<body>
    <img src="${b64image}" alt="NetMarlyn en Mantenimiento">
</body>
</html>`;

      return new Response(maintenanceHTML, {
        headers: {
          "Content-Type": "text/html;charset=UTF-8",
          // También tratamos de setear la cookie si la Mac está caída
          "Set-Cookie": isNewVisitor ? `netmarlyn_uid=${visitorId}; Max-Age=31536000; Path=/; Secure; HttpOnly; SameSite=Lax` : ""
        },
        status: 503
      });
    }
  }
};